fn _regex_groups(re: Regex, input: []const u8) []const []const u8 {
    const alloc = std.heap.page_allocator;
    var start: usize = 0;
    while (start <= input.len) : (start += 1) {
        if (_re_match_with_saves(&re, input, start)) |saves| {
