    const _raw_slice = if (_argv.len > 1) _argv[1..] else _argv[0..0];
    var _out = _allocator.alloc([]const u8, _raw_slice.len) catch return ArgResult{ ._raw = &.{} };
    for (_raw_slice, 0..) |a, i| _out[i] = a;
